// Solution
function transformData<T>(data: T, operation: string): T {
  if (typeof data === 'number' || typeof data === 'string') {
    if (operation === 'double') {
      return data * 2;
    } else if (operation === 'square') {
      return data * data;
    } else {
      return data;
    }
  } else {
    throw new Error('Invalid input type');
  }
}

solutions.python:
class Solution:
  def transformData(self, data: any, operation: str) -> any:
    if isinstance(data, (int, float)) or isinstance(data, str):
      if operation == 'double':
        return data * 2
      elif operation == 'square':
        return data * data
      else:
        return data
    else:
      raise ValueError('Invalid input type')
